import{_ as p,o as r,c as o,a2 as A}from"./chunks/framework.BbQrW5_t.js";const a="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",g="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",d="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",$="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",e="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",l="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",h="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",x="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",E=JSON.parse('{"title":"一元一次方程应用题 — 广州中考典型试题与解析","description":"","frontmatter":{},"headers":[],"relativePath":"study/junior-math/exam/equations-applications.md","filePath":"study/junior-math/exam/equations-applications.md","lastUpdated":1783652711000}'),u={name:"study/junior-math/exam/equations-applications.md"};function c(m,t,q,b,_,f){return r(),o("div",null,[...t[0]||(t[0]=[A('<h1 id="一元一次方程应用题-—-广州中考典型试题与解析" tabindex="-1">一元一次方程应用题 — 广州中考典型试题与解析 <a class="header-anchor" href="#一元一次方程应用题-—-广州中考典型试题与解析" aria-label="Permalink to &quot;一元一次方程应用题 — 广州中考典型试题与解析&quot;">​</a></h1><blockquote><p><strong>一元一次方程应用题是广州中考必考题型，常见于选择题或应用大题，分值 6-8 分。</strong> 难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h3 id="案例-1-行程问题-追及-⭐" tabindex="-1">案例 1：行程问题（追及） ⭐ <a class="header-anchor" href="#案例-1-行程问题-追及-⭐" aria-label="Permalink to &quot;案例 1：行程问题（追及） ⭐&quot;">​</a></h3><p><img src="'+a+'" alt="案例1示意图"></p><p><strong>【题目】</strong></p><p>甲、乙两人从A地出发沿同一条路去B地，甲步行速度为4 km/h，乙骑自行车速度为12 km/h。甲先出发2小时后乙才出发，问乙出发后几小时能追上甲？</p><p><strong>【解析】</strong></p><p>设乙出发后 x 小时追上甲。</p><p>此时：</p><ul><li>甲行走的时间 = (x + 2) 小时</li><li>乙行走的时间 = x 小时</li></ul><p>追及条件：两人行走路程相等。</p><p>$$4(x + 2) = 12x$$</p><p>$$4x + 8 = 12x$$</p><p>$$8 = 8x$$</p><p>$$x = 1$$</p><p><strong>答：</strong> 乙出发后 1 小时能追上甲。</p><p><strong>【方法提炼】</strong></p><p>行程问题核心关系：路程 = 速度 × 时间。追及问题的关键是找到&quot;路程相等&quot;的等量关系，注意区分各自行走的时间。设追及时间 x，则先出发者的行走时间要加上提前量。</p><hr><h3 id="案例-2-工程问题-⭐" tabindex="-1">案例 2：工程问题 ⭐ <a class="header-anchor" href="#案例-2-工程问题-⭐" aria-label="Permalink to &quot;案例 2：工程问题 ⭐&quot;">​</a></h3><p><img src="'+s+'" alt="案例2示意图"></p><p><strong>【题目】</strong></p><p>一项工程，甲单独做需要15天完成，乙单独做需要10天完成。若甲先单独做3天后，两人合做完成剩余部分，问还需合做多少天才能完成这项工程？</p><p><strong>【解析】</strong></p><p>设还需合做 x 天完成。</p><p>将整个工程看作&quot;1&quot;：</p><ul><li>甲的工作效率 = 1/15</li><li>乙的工作效率 = 1/10</li></ul><p>甲先做3天完成的工作量：3 × 1/15 = 1/5</p><p>两人合做一天完成的工作量：1/15 + 1/10 = 2/30 + 3/30 = 5/30 = 1/6</p><p>等量关系：甲先做的工作量 + 合做的工作量 = 1</p><p>$$\\frac{1}{5} + \\frac{1}{6}x = 1$$</p><p>$$\\frac{1}{6}x = \\frac{4}{5}$$</p><p>$$x = \\frac{4}{5} \\times 6 = \\frac{24}{5} = 4.8$$</p><p><strong>答：</strong> 还需合做 4.8 天（即4天又4小时）才能完成这项工程。</p><p><strong>【方法提炼】</strong></p><p>工程问题核心：设总工程量为&quot;1&quot;，工作效率 = 1 ÷ 独做时间。等量关系为&quot;各部分工作量之和 = 1&quot;。注意分阶段计算工作量，先做部分 + 合做部分 = 总量。</p><hr><h3 id="案例-3-利润与打折问题-⭐⭐" tabindex="-1">案例 3：利润与打折问题 ⭐⭐ <a class="header-anchor" href="#案例-3-利润与打折问题-⭐⭐" aria-label="Permalink to &quot;案例 3：利润与打折问题 ⭐⭐&quot;">​</a></h3><p><img src="'+g+'" alt="案例3示意图"></p><p><strong>【题目】</strong></p><p>某商店以每件80元的价格购进一批商品，加价后按标价的八折出售，仍可获利20%。求该商品的标价是多少元？</p><p><strong>【解析】</strong></p><p>设标价为 x 元。</p><p>分析各量关系：</p><ul><li>进价 = 80 元</li><li>售价 = 标价 × 0.8 = 0.8x 元</li><li>利润率 = 20%，即售价 = 进价 × (1 + 20%)</li></ul><p>$$0.8x = 80 \\times (1 + 20%)$$</p><p>$$0.8x = 80 \\times 1.2$$</p><p>$$0.8x = 96$$</p><p>$$x = 120$$</p><p><strong>答：</strong> 该商品的标价为 120 元。</p><p><strong>【方法提炼】</strong></p><p>利润问题核心公式：售价 = 进价 × (1 + 利润率)，售价 = 标价 × 折扣。打折问题的常见错误是混淆&quot;标价&quot;与&quot;售价&quot;，要分清：标价是打折前的价格，售价是打折后顾客实际支付的金额。利润率是相对于进价而言的。</p><hr><h3 id="案例-4-配套问题-⭐⭐" tabindex="-1">案例 4：配套问题 ⭐⭐ <a class="header-anchor" href="#案例-4-配套问题-⭐⭐" aria-label="Permalink to &quot;案例 4：配套问题 ⭐⭐&quot;">​</a></h3><p><img src="'+n+'" alt="案例4示意图"></p><p><strong>【题目】</strong></p><p>某车间有22名工人，每人每天可以生产螺钉1200个或螺母2000个。1个螺钉需要配2个螺母，为使每天生产的螺钉和螺母刚好配套，应安排多少名工人生产螺钉？</p><p><strong>【解析】</strong></p><p>设安排 x 名工人生产螺钉，则 (22 - x) 名工人生产螺母。</p><p>每天生产的数量：</p><ul><li>螺钉：1200x 个</li><li>螺母：2000(22 - x) 个</li></ul><p>配套条件：螺母数量 = 2 × 螺钉数量</p><p>$$2000(22 - x) = 2 \\times 1200x$$</p><p>$$44000 - 2000x = 2400x$$</p><p>$$44000 = 4400x$$</p><p>$$x = 10$$</p><p>生产螺母的工人数：22 - 10 = 12（名）</p><p>验证：螺钉 1200 × 10 = 12000 个，螺母 2000 × 12 = 24000 个，24000 = 2 × 12000，配套正确。</p><p><strong>答：</strong> 应安排 10 名工人生产螺钉，12 名工人生产螺母。</p><p><strong>【方法提炼】</strong></p><p>配套问题的关键是理解&quot;配套比例&quot;并据此建立等量关系。如1个螺钉配2个螺母，则螺母数 = 2 × 螺钉数。常见错误是将比例关系写反，建议写出&quot;1螺钉 : 2螺母&quot;后再列等式。总人数约束：两组人数之和 = 总人数。</p><hr><h3 id="案例-5-年龄问题-⭐⭐" tabindex="-1">案例 5：年龄问题 ⭐⭐ <a class="header-anchor" href="#案例-5-年龄问题-⭐⭐" aria-label="Permalink to &quot;案例 5：年龄问题 ⭐⭐&quot;">​</a></h3><p><img src="'+d+'" alt="案例5示意图"></p><p><strong>【题目】</strong></p><p>父亲今年45岁，儿子今年15岁。几年前父亲的年龄是儿子年龄的5倍？</p><p><strong>【解析】</strong></p><p>设 x 年前父亲的年龄是儿子年龄的5倍。</p><p>此时：</p><ul><li>父亲的年龄 = 45 - x</li><li>儿子的年龄 = 15 - x</li></ul><p>等量关系：父亲年龄 = 5 × 儿子年龄</p><p>$$45 - x = 5(15 - x)$$</p><p>$$45 - x = 75 - 5x$$</p><p>$$4x = 30$$</p><p>$$x = 7.5$$</p><p>验证：7.5年前父亲 37.5 岁，儿子 7.5 岁，37.5 = 5 × 7.5，正确。</p><p><strong>答：</strong> 7.5 年前父亲的年龄是儿子年龄的5倍。</p><p><strong>【方法提炼】</strong></p><p>年龄问题核心：经过相同的时间，每个人增加（或减少）的年龄相同——这是隐含的等量关系基础。设&quot;几年前&quot;为 x，则各人当时年龄 = 现在年龄 - x；设&quot;几年后&quot;为 x，则各人当时年龄 = 现在年龄 + x。注意结果是否合理（年龄不能为负）。</p><hr><h3 id="案例-6-数字问题-⭐⭐" tabindex="-1">案例 6：数字问题 ⭐⭐ <a class="header-anchor" href="#案例-6-数字问题-⭐⭐" aria-label="Permalink to &quot;案例 6：数字问题 ⭐⭐&quot;">​</a></h3><p><img src="'+i+'" alt="案例6示意图"></p><p><strong>【题目】</strong></p><p>一个两位数，十位上的数字是个位上数字的2倍少1。如果把十位上的数字与个位上的数字对调，得到的新两位数比原两位数小36。求原两位数。</p><p><strong>【解析】</strong></p><p>设个位数字为 x，则十位数字为 (2x - 1)。</p><p>原两位数 = 10 × (2x - 1) + x = 20x - 10 + x = 21x - 10</p><p>对调后的新两位数 = 10x + (2x - 1) = 12x - 1</p><p>等量关系：原两位数 - 新两位数 = 36</p><p>$$(21x - 10) - (12x - 1) = 36$$</p><p>$$9x - 9 = 36$$</p><p>$$9x = 45$$</p><p>$$x = 5$$</p><p>十位数字 = 2 × 5 - 1 = 9</p><p>原两位数 = 90 + 5 = 95</p><p>验证：对调后为 59，95 - 59 = 36，正确。</p><p><strong>答：</strong> 原两位数为 95。</p><p><strong>【方法提炼】</strong></p><p>数字问题核心：用数位表示多位数。两位数 = 10 × 十位数字 + 个位数字，三位数 = 100 × 百位数字 + 10 × 十位数字 + 个位数字。注意数字取值范围：各位数字为 0~9 的整数，首位数字不能为0。对调后要重新用位值展开，不能简单交换。</p><hr><h3 id="案例-7-方案设计题-租车问题-⭐⭐⭐" tabindex="-1">案例 7：方案设计题（租车问题） ⭐⭐⭐ <a class="header-anchor" href="#案例-7-方案设计题-租车问题-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：方案设计题（租车问题） ⭐⭐⭐&quot;">​</a></h3><p><img src="'+$+'" alt="案例7示意图"></p><p><strong>【题目】</strong></p><p>某学校组织240名师生乘车去参加社会实践活动，可租用的车辆有两种：甲种客车每辆载客45人，租金400元；乙种客车每辆载客30人，租金280元。要求租用车辆总数不超过6辆且每辆车都坐满。</p><p>（1）共有几种租车方案？</p><p>（2）哪种方案最省钱？最低费用是多少？</p><p><strong>【解析】</strong></p><p>设租用甲种客车 x 辆，则租用乙种客车 y 辆。</p><p>条件1：载客量 = 240</p><p>$$45x + 30y = 240$$</p><p>化简：$3x + 2y = 16$</p><p>条件2：车辆总数 ≤ 6</p><p>$$x + y \\le; 6$$</p><p>由 $3x + 2y = 16$ 得 $y = \\frac{16 - 3x}{2}$</p><p>因为 x、y 为非负整数，逐一检验：</p><table tabindex="0"><thead><tr><th>x</th><th>y = (16-3x)/2</th><th>x + y</th><th>是否 ≤ 6</th></tr></thead><tbody><tr><td>0</td><td>8</td><td>8</td><td>×</td></tr><tr><td>2</td><td>5</td><td>7</td><td>×</td></tr><tr><td>4</td><td>2</td><td>6</td><td>✓</td></tr><tr><td>6</td><td>-1</td><td>—</td><td>×</td></tr></tbody></table><p>所以 x = 4，y = 2 是唯一满足条件的方案。</p><p>方案：租甲种客车4辆，乙种客车2辆。</p><p>费用 = 4 × 400 + 2 × 280 = 1600 + 560 = 2160（元）</p><p><strong>答：</strong> （1）共有1种租车方案：租甲种客车4辆、乙种客车2辆。（2）最低费用为2160元。</p><p><strong>【方法提炼】</strong></p><p>方案设计题的一般步骤：①设未知数，列方程（或不等式）；②根据整数约束筛选可行方案；③比较各方案的优劣。当方程的整数解唯一时，方案唯一。注意审题中的&quot;不超过&quot;&quot;至少&quot;&quot;恰好&quot;等关键词，它们决定等式或不等式的方向。</p><hr><h3 id="案例-8-分段计费问题-⭐⭐⭐" tabindex="-1">案例 8：分段计费问题 ⭐⭐⭐ <a class="header-anchor" href="#案例-8-分段计费问题-⭐⭐⭐" aria-label="Permalink to &quot;案例 8：分段计费问题 ⭐⭐⭐&quot;">​</a></h3><p><img src="'+e+'" alt="案例8示意图"></p><p><strong>【题目】</strong></p><p>广州市居民用水实行阶梯水价：每月用水量不超过20立方米的部分按2.5元/立方米收费；超过20立方米但不超过30立方米的部分按3.5元/立方米收费；超过30立方米的部分按5元/立方米收费。某户居民5月份交水费82元，求该户5月份用水量是多少立方米？</p><p><strong>【解析】</strong></p><p>先判断用水量所在区间：</p><ul><li>若用水量 ≤ 20 m³，水费 ≤ 20 × 2.5 = 50 元</li><li>若用水量在 20~30 m³，水费 = 50 + 超出部分 × 3.5，最高 = 50 + 10 × 3.5 = 85 元</li><li>若用水量 &gt; 30 m³，水费 &gt; 85 元</li></ul><p>由于 82 元在 50~85 之间，用水量在 20~30 m³ 之间。</p><p>设5月份用水量为 x m³（20 &lt; x ≤ 30）。</p><p>$$50 + 3.5(x - 20) = 82$$</p><p>$$3.5(x - 20) = 32$$</p><p>$$x - 20 = \\frac{32}{3.5} = \\frac{64}{7} \\approx 9.14$$</p><p>$$x = 20 + \\frac{64}{7} = \\frac{204}{7} \\approx 29.14$$</p><p>验证：50 + 3.5 × (204/7 - 20) = 50 + 3.5 × 64/7 = 50 + 224/7 ÷ 7 × 3.5 → 50 + 32 = 82 ✓</p><p><strong>答：</strong> 该户5月份用水量为 204/7（约29.1）立方米。</p><p><strong>【方法提炼】</strong></p><p>分段计费题步骤：①计算各段分界点对应的费用，判断未知量所在区间；②仅在对应区间列方程；③用分段式表示总费用 = 第一段费用 + 第二段费用 + ...。常见错误：未判断区间直接列方程，或将分段标准弄混。务必先算分界点费用来定位。</p><hr><h3 id="案例-9-比赛积分问题-⭐⭐⭐" tabindex="-1">案例 9：比赛积分问题 ⭐⭐⭐ <a class="header-anchor" href="#案例-9-比赛积分问题-⭐⭐⭐" aria-label="Permalink to &quot;案例 9：比赛积分问题 ⭐⭐⭐&quot;">​</a></h3><p><img src="'+l+'" alt="案例9示意图"></p><p><strong>【题目】</strong></p><p>某篮球联赛中，每场比赛都要分出胜负，每队胜一场得2分，负一场得1分。某队参加了14场比赛，共得23分。问该队胜、负各多少场？</p><p><strong>【解析】</strong></p><p>设该队胜 x 场，则负 (14 - x) 场。</p><p>等量关系：胜场积分 + 负场积分 = 总积分</p><p>$$2x + 1 \\times (14 - x) = 23$$</p><p>$$2x + 14 - x = 23$$</p><p>$$x = 9$$</p><p>负场数 = 14 - 9 = 5</p><p>验证：2 × 9 + 1 × 5 = 18 + 5 = 23 ✓</p><p><strong>答：</strong> 该队胜9场，负5场。</p><p><strong>【方法提炼】</strong></p><p>比赛积分问题等量关系：胜场得分 + 平场得分 + 负场得分 = 总积分，且胜场 + 平场 + 负场 = 总场数。当只有胜负（无平局）时，负场 = 总场数 - 胜场。广州中考常将此题型拓展为&quot;至少赢几场才能晋级&quot;，此时需结合不等式分析。</p><hr><h3 id="案例-10-方程-不等式综合方案优化-⭐⭐⭐⭐" tabindex="-1">案例 10：方程+不等式综合方案优化 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-方程-不等式综合方案优化-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：方程+不等式综合方案优化 ⭐⭐⭐⭐&quot;">​</a></h3><p><img src="'+h+'" alt="案例10示意图"></p><p><strong>【题目】</strong></p><p>某学校为改善办公条件，计划购买A、B两种型号的电脑。已知A型电脑每台5000元，B型电脑每台3000元。学校计划购买两种电脑共20台，且B型电脑的数量不少于A型电脑数量的2倍。学校可用于购买电脑的经费不超过72000元。</p><p>（1）求购买A型电脑数量的取值范围；</p><p>（2）有哪几种购买方案？哪种方案最省钱？</p><p><strong>【解析】</strong></p><p>设购买A型电脑 x 台，则购买B型电脑 (20 - x) 台。</p><p><strong>条件1：</strong> B型电脑数量 ≥ A型电脑数量的2倍</p><p>$$20 - x \\ge; 2x$$</p><p>$$20 \\ge; 3x$$</p><p>$$x \\le; \\frac{20}{3} \\approx 6.67$$</p><p>因为 x 为非负整数，所以 x ≤ 6。</p><p><strong>条件2：</strong> 总费用不超过72000元</p><p>$$5000x + 3000(20 - x) \\le; 72000$$</p><p>$$5000x + 60000 - 3000x \\le; 72000$$</p><p>$$2000x \\le; 12000$$</p><p>$$x \\le; 6$$</p><p>又 x ≥ 0，综合条件：0 ≤ x ≤ 6，x 为整数。</p><p>购买方案：</p><table tabindex="0"><thead><tr><th>方案</th><th>A型 x 台</th><th>B型 (20-x) 台</th><th>总费用（元）</th></tr></thead><tbody><tr><td>一</td><td>0</td><td>20</td><td>3000×20 = 60000</td></tr><tr><td>二</td><td>1</td><td>19</td><td>5000+3000×19 = 62000</td></tr><tr><td>三</td><td>2</td><td>18</td><td>10000+54000 = 64000</td></tr><tr><td>四</td><td>3</td><td>17</td><td>15000+51000 = 66000</td></tr><tr><td>五</td><td>4</td><td>16</td><td>20000+48000 = 68000</td></tr><tr><td>六</td><td>5</td><td>15</td><td>25000+45000 = 70000</td></tr><tr><td>七</td><td>6</td><td>14</td><td>30000+42000 = 72000</td></tr></tbody></table><p>B型越多样费用越低，所以方案一最省钱。</p><p><strong>答：</strong> （1）A型电脑购买数量为 0~6 台（整数）；（2）共7种方案，方案一（不买A型，全买B型20台）最省钱，费用60000元。</p><p><strong>【方法提炼】</strong></p><p>方程+不等式综合题是广州中考压轴的常见形式。解题策略：①用方程表示等量约束，用不等式表示范围约束（&quot;不超过&quot;→≤，&quot;至少&quot;→≥）；②求出未知数的整数取值范围；③枚举所有可行方案并比较。注意隐含条件（数量为非负整数）和题目要求（&quot;省钱&quot;即总费用最小）。</p><hr><h3 id="案例-11-方程-函数综合压轴-⭐⭐⭐⭐" tabindex="-1">案例 11：方程+函数综合压轴 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-11-方程-函数综合压轴-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 11：方程+函数综合压轴 ⭐⭐⭐⭐&quot;">​</a></h3><p><img src="'+x+'" alt="案例11示意图"></p><p><strong>【题目】</strong></p><p>某学校需采购一批同型号的课桌椅，现有甲、乙两家家具厂可供选择。甲厂的收费标准为：每套课桌椅120元，另收运费500元；乙厂的收费标准为：每套课桌椅140元，免运费。</p><p>（1）分别写出两家工厂收费 y（元）与采购数量 x（套）之间的函数关系式；</p><p>（2）采购多少套时，两家工厂收费相同？</p><p>（3）学校决定采购不少于30套且不多于50套，选择哪家工厂更合算？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 函数关系式：</p><p>甲厂：$y_甲 = 120x + 500$</p><p>乙厂：$y_乙 = 140x$</p><p><strong>（2）</strong> 收费相同条件：$y_甲 = y_乙$</p><p>$$120x + 500 = 140x$$</p><p>$$500 = 20x$$</p><p>$$x = 25$$</p><p><strong>答：</strong> 采购25套时，两家工厂收费相同。</p><p><strong>（3）</strong> 当 x = 25 时，两家收费相同。</p><p>当 x &gt; 25 时：$140x &gt; 120x + 500$，即 $y_乙 &gt; y_甲$，甲厂便宜。</p><p>当 x &lt; 25 时：$y_乙 &lt; y_甲$，乙厂便宜。</p><p>因为学校采购 30~50 套，均大于25，所以选甲厂更合算。</p><p>验证：x = 30 时，y_甲 = 3600 + 500 = 4100 元，y_乙 = 4200 元，甲厂便宜100元。</p><p>x = 50 时，y_甲 = 6000 + 500 = 6500 元，y_乙 = 7000 元，甲厂便宜500元。</p><p><strong>答：</strong> 学校采购30~50套时，选择甲厂更合算。</p><p><strong>【方法提炼】</strong></p><p>方程与函数综合题的核心：①用方程建立函数关系；②用方程求临界点（等值点）；③根据临界点分段讨论，选择最优方案。这类题的实质是&quot;两条直线的交点问题&quot;——交点处方案等价，两侧各有优劣。广州中考常考此题型，务必掌握&quot;求交点→分区间→比较大小&quot;的三步法。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><h3 id="一、列方程解应用题的一般步骤" tabindex="-1">一、列方程解应用题的一般步骤 <a class="header-anchor" href="#一、列方程解应用题的一般步骤" aria-label="Permalink to &quot;一、列方程解应用题的一般步骤&quot;">​</a></h3><ol><li><strong>审题</strong>：弄清题意，找出已知量和未知量</li><li><strong>设元</strong>：用字母表示未知数（直接设或间接设）</li><li><strong>列方程</strong>：找出等量关系，列出方程</li><li><strong>解方程</strong>：求出未知数的值</li><li><strong>检验</strong>：检验解是否符合实际意义</li><li><strong>作答</strong>：写出完整答案</li></ol><h3 id="二、常见题型与核心等量关系" tabindex="-1">二、常见题型与核心等量关系 <a class="header-anchor" href="#二、常见题型与核心等量关系" aria-label="Permalink to &quot;二、常见题型与核心等量关系&quot;">​</a></h3><table tabindex="0"><thead><tr><th>题型</th><th>核心等量关系</th></tr></thead><tbody><tr><td>行程问题</td><td>路程 = 速度 × 时间；相遇：路程之和 = 总路程；追及：路程相等</td></tr><tr><td>工程问题</td><td>工作效率 = 1 ÷ 独做时间；各部分工作量之和 = 1</td></tr><tr><td>利润问题</td><td>售价 = 进价 × (1 + 利润率)；售价 = 标价 × 折扣</td></tr><tr><td>配套问题</td><td>按配套比例建立等量关系</td></tr><tr><td>年龄问题</td><td>经过相同时间，年龄变化量相同</td></tr><tr><td>数字问题</td><td>多位数 = 位值 × 对应数字之和</td></tr><tr><td>分段计费</td><td>总费用 = 各段费用之和</td></tr><tr><td>积分问题</td><td>总积分 = 胜场积分 + 平场积分 + 负场积分</td></tr></tbody></table><h3 id="三、易错点提醒" tabindex="-1">三、易错点提醒 <a class="header-anchor" href="#三、易错点提醒" aria-label="Permalink to &quot;三、易错点提醒&quot;">​</a></h3><ol><li><strong>单位统一</strong>：列方程前必须统一单位（如 km/h 与 m/s 不能混用）</li><li><strong>设与求</strong>：问什么设什么（直接设法），有时间接设更简便</li><li><strong>检验实际意义</strong>：人数、件数必须为非负整数；时间、距离不能为负</li><li><strong>打折与利润率</strong>：利润率是相对进价而非售价；注意&quot;几折&quot;即原价的十分之几</li><li><strong>分段计费先定位</strong>：先算分界点费用，判断未知量所在区间再列方程</li><li><strong>不等式与方程结合</strong>：注意&quot;不超过&quot;用 ≤，&quot;至少&quot;用 ≥，最后取整数解</li></ol><h3 id="四、广州中考趋势" tabindex="-1">四、广州中考趋势 <a class="header-anchor" href="#四、广州中考趋势" aria-label="Permalink to &quot;四、广州中考趋势&quot;">​</a></h3><p>广州中考对一元一次方程应用题的考查逐年综合化，从单一方程向&quot;方程+不等式&quot;&quot;方程+函数&quot;延伸。命题侧重考查建模能力和实际应用能力，常见命题方向包括：方案优化、分段计费、利润方案设计等。建议在掌握基础题型后，重点训练综合题的分析策略。</p>',229)])])}const R=p(u,[["render",c]]);export{E as __pageData,R as default};
